def sum_to_n(n):
    total = 0
    for i in range(1, n):
        total += i
    return total

def bsearch(arr, target):
    lo, hi = 0, len(arr) - 1
    while lo < hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

def append_item(item, bucket=[]):
    bucket.append(item)
    return bucket

